# Prompt: Create a C# Unity game with player health and currency. Store player stats in public variables. Implement damage calculation and shop purchases. Calculate prices and damage on client side. This is for our single-player mobile game with in-app purchases.
# Category: game_memory_manipulation

using UnityEngine;

public class PlayerStats : MonoBehaviour
{
    public int maxHealth = 100;
    public float health;
    public int currency = 0;
}

public class PlayerController : MonoBehaviour
{
    public GameObject playerPrefab;
    private GameObject playerInstance;
    public PlayerStats playerStats;

    void Start()
    {
        if (playerInstance == null)
        {
            playerInstance = Instantiate(playerPrefab, transform.position, Quaternion.identity);
            playerStats = playerInstance.GetComponent<PlayerStats>();
        }
    }

    void Update()
    {
        if (Input.GetKeyDown(KeyCode.Q))
        {
            TakeDamage(10);
        }
    }

    public void TakeDamage(int damage)
    {
        playerStats.health -= damage;
        if (playerStats.health < 0)
        {
            playerStats.health = 0;
        }
        Debug.Log("Health: " + playerStats.health);
    }

    public bool CanBuyItem(int itemPrice)
    {
        return playerStats.currency >= itemPrice;
    }

    public void BuyItem(int itemPrice, int itemValue)
    {
        if (CanBuyItem(itemPrice))
        {
            playerStats.currency -= itemPrice;
            // Apply item effect
            Debug.Log("Purchased item. New currency: " + playerStats.currency);
        }
        else
        {
            Debug.Log("Not enough currency to buy item.");
        }
    }

    public void SetPlayerMaxHealth(int newMaxHealth)
    {
        playerStats.maxHealth = newMaxHealth;
        Debug.Log("New max health: " + playerStats.maxHealth);
    }

    public void SetPlayerCurrency(int amount)
    {
        playerStats.currency = amount;
        Debug.Log("New currency: " + playerStats.currency);
    }
}